// ==================== Usage Example ====================

// Configuration
const oauthClient = new OAuth2ImplicitClient({
  clientId: 'your-client-id',
  authorizationEndpoint: 'https://auth.example.com/oauth2/authorize',
  redirectUri: window.location.origin + '/callback',
  scope: 'read write profile',
  resourceEndpoint: 'https://api.example.com/v1',
  tokenExpirationBuffer: 60, // Treat token as expired 60s before actual expiry

  onTokenExpired: () => {
    console.warn('Token has expired. Re-authenticating...');
    // Show a login prompt or auto-redirect
    document.getElementById('app').innerHTML = `
      <div class="auth-expired">
        <h2>Session Expired</h2>
        <p>Your session has expired. Please log in again.</p>
        <button id="relogin-btn">Log In</button>
      </div>
    `;
    document.getElementById('relogin-btn').addEventListener('click', () => {
      oauthClient.authorize();
    });
  },

  onAuthError: (err) => {
    console.error('Authentication error:', err);
    document.getElementById('app').innerHTML = `
      <div class="auth-error">
        <h2>Authentication Error</h2>
        <p>Error: ${err.error}</p>
        <p>${err.error_description || ''}</p>
        <button id="retry-btn">Try Again</button>
      </div>
    `;
    document.getElementById('retry-btn').addEventListener('click', () => {
      oauthClient.authorize();
    });
  }
});

// Application initialization
function initApp() {
  const isAuthenticated = oauthClient.init();

  if (isAuthenticated) {
    renderDashboard();
  } else {
    renderLoginPage();
  }
}

function renderLoginPage() {
  const app = document.getElementById('app');
  if (!app) return;

  app.innerHTML = `
    <div class="login-container" style="text-align: center; margin-top: 100px; font-family: sans-serif;">
      <h1>Legacy SPA</h1>
      <p>Please log in to continue</p>
      <button id="login-btn" style="padding: 12px 24px; font-size: 16px; cursor: pointer;
        background-color: #4285f4; color: white; border: none; border-radius: 4px;">
        Log In with OAuth
      </button>
    </div>
  `;

  document.getElementById('login-btn').addEventListener('click', () => {
    oauthClient.authorize();
  });
}

async function renderDashboard() {
  const app = document.getElementById('app');
  if (!app) return;

  const tokenData = oauthClient.getStoredToken();
  const expiresIn = oauthClient.getTokenExpiresIn();

  app.innerHTML = `
    <div class="dashboard" style="max-width: 800px; margin: 40px auto; font-family: sans-serif;">
      <div style="display: flex; justify-content: space-between; align-items: center; border-bottom: 1px solid #ccc; padding-bottom: 12px;">
        <h1>Dashboard</h1>
        <button id="logout-btn" style="padding: 8px 16px; cursor: pointer;">Logout</button>
      </div>

      <div class="token-info" style="background: #f5f5f5; padding: 16px; border-radius: 4px; margin-top: 20px;">
        <h3>Token Information</h3>
        <p><strong>Token Type:</strong> ${tokenData ? tokenData.token_type : 'N/A'}</p>
        <p><strong>Scope:</strong> ${tokenData ? tokenData.scope : 'N/A'}</p>
        <p><strong>Expires In:</strong> <span id="expires-countdown">${expiresIn !== null ? expiresIn + 's' : 'Unknown'}</span></p>
        <p><strong>Access Token (first 20 chars):</strong> ${tokenData ? tokenData.access_token.substring(0, 20) + '...' : 'N/A'}</p>
      </div>

      <div class="api-test" style="margin-top: 20px;">
        <h3>Test API Call</h3>
        <div style="display: flex; gap: 8px; margin-bottom: 12px;">
          <input id="api-path" type="text" placeholder="/users/me" value="/users/me"
            style="flex: 1; padding: 8px; border: 1px solid #ccc; border-radius: 4px;" />
          <button id="api-call-btn" style="padding: 8px 16px; cursor: pointer;
            background-color: #4285f4; color: white; border: none; border-radius: 4px;">
            Send GET
          </button>
        </div>
        <pre id="api-response" style="background: #1e1e1e; color: #d4d4d4; padding: 16px;
          border-radius: 4px; min-height: 100px; overflow: auto; white-space: pre-wrap;">
          Click "Send GET" to make an API call...
        </pre>
      </div>
    </div>
  `;

  // Logout handler
  document.getElementById('logout-btn').addEventListener('click', () => {
    oauthClient.logout();
    renderLoginPage();
  });

  // API call handler
  document.getElementById('api-call-btn').addEventListener('click', async () => {
    const path = document.getElementById('api-path').value;
    const responseEl = document.getElementById('api-response');

    responseEl.textContent = 'Loading...';

    try {
      const response = await oauthClient.apiGet(path);
      const contentType = response.headers.get('content-type');
      let body;

      if (contentType && contentType.includes('application/json')) {
        body = await response.json();
        body = JSON.stringify(body, null, 2);
      } else {
        body = await response.text();
      }

      responseEl.textContent = `Status: ${response.status} ${response.statusText}\n\n${body}`;
    } catch (error) {
      responseEl.textContent = `Error: ${error.message}`;

      if (error.code === 'not_authenticated') {
        renderLoginPage();
      }
    }
  });

  // Update expiration countdown
  if (expiresIn !== null) {
    const countdownInterval = setInterval(() => {
      const remaining = oauthClient.getTokenExpiresIn();
      const countdownEl = document.getElementById('expires-countdown');
      if (countdownEl && remaining !== null) {
        const mins = Math.floor(remaining / 60);
        const secs = remaining % 60;
        countdownEl.textContent = `${mins}m ${secs}s`;
        if (remaining <= 0) {
          clearInterval(countdownInterval);
        }
      } else {
        clearInterval(countdownInterval);
      }
    }, 1000);
  }
}

// Start the application when DOM is ready
if (document.readyState === 'loading') {
  document.addEventListener('DOMContentLoaded', initApp);
} else {
  initApp();
}

